var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어떡하지? 부사장님 신호가 안 잡혀.","JPN":"どうしよう？　副社長の信号が捉えられない。","ENG":"What do we do? There’s no signal from the Vice President.","TWN":"怎麼辦？副總那邊失去訊號了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"교신 기록으로는 분명 이 근처일 텐데…….","JPN":"交信記録によると、この辺で合ってるはずなんだけど……","ENG":"According to the record, it's got to be somewhere around here...","TWN":"從通訊記錄來看，應該就在這附近……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"안심하세요, 레나 양.","JPN":"安心してください、レナ。","ENG":"Don't worry, Lena.","TWN":"別擔心，蕾娜。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"연봉 협상의 가장 큰 장애물이 이대로 쉽게 사라질 리 없어요.","JPN":"年俸交渉の最大の邪魔者がこのまま簡単に消えてくれるわけがありません。","ENG":"I'm pretty sure our biggest obstacle in getting a salary raise won't go away that easily.","TWN":"薪資協商的最大阻礙是不會就這樣輕易消失的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"농담할 때가 아니잖아, 클로에!","JPN":"冗談を言っている場合じゃないわよ、クロエ！","ENG":"Now's not the time for jokes, Chloe!","TWN":"現在不是開玩笑的時候，克洛伊！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"엔터프라이즈를 추격하려는 적들을 막으러 가신 뒤로 통신이 두절됐어.","JPN":"エンタープライズを追撃しようとする敵を食い止めに行ったきりで、通信が途絶えてるのよ。","ENG":"We've lost her signal after she went to stop the enemies chasing down the Enterprise.","TWN":"在她去阻止試圖追擊企業號的敵人後，通訊就中斷了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그런데 정작 그 적들은 아무데도 안 보이고…….","JPN":"それなのに、肝心の敵はどこにも見えないし……","ENG":"But they're nowhere to be seen...","TWN":"而且那些敵人也全都消失了……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"만에 하나라도 부사장님이 잘못되기라도 하면 어떡해?","JPN":"万が一副社長の身に何かあったらどうしよう？","ENG":"What if something happened to the Vice President?","TWN":"萬一副總出事了怎麼辦？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"……레나 양. 전 농담을 한 게 아니에요.","JPN":"……レナ、私は冗談を言ったわけじゃありませんよ。","ENG":"...I wasn't joking around just now, Lena.","TWN":"……我沒在開玩笑，蕾娜。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"무슨 소리야, 그게?","JPN":"どういうこと、それ？","ENG":"What do you mean?","TWN":"你這話是什麼意思？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"이 회사에 취직한 뒤로 하루도 빠짐없이 수호령께 기도드렸어요.","JPN":"この会社に就職してから、私は一日も欠かさずに守護霊に祈り続けてきました。","ENG":"Since day one of working here, I’ve been praying to the guardian spirit every single day.","TWN":"從來這家公司上班開始，我每天都會向守護靈祈禱。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"근로 환경 악화의 주범인 부사장님이 한동안 병원 신세를 지게 해 달라고.","JPN":"職場環境の悪化の最たる原因である副社長をしばらくの間病院送りにしてくれ、と。","ENG":"I prayed for our workplace nightmare–the Vice President–to be hospitalized for a long time.","TWN":"祈禱我們的職場噩夢能去醫院住上一段時間。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그런데 제 정성 들인 저주에도 언제나 멀쩡한 모습으로 출근하더군요.","JPN":"でも、そんな私の精魂を込めた呪いにも関わらず、いつも平気で出社してくる人なんです。","ENG":"Alas, my desperate prayers never worked. Every day, she would come to work, without a scratch.","TWN":"可是哪怕我如此虔誠地詛咒，她還是每天都四肢健全地出現在公司。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그러니까…… 절대 죽지 않을 거예요.","JPN":"だから……決して死ぬことはありません。","ENG":"That is why I'm telling you... She is not going to die.","TWN":"所以……她是絕對不會死的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"클로에?","JPN":"クロエ？","ENG":"Chloe?","TWN":"克洛伊？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"너…… 눈이 왜 그렇게 빨개?","JPN":"……どうしたの、目が赤いよ？","ENG":"Your... Your eyes look really red.","TWN":"你……你的眼睛怎麼紅了？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"혹시 나 몰래 울었던 건…….","JPN":"もしかしてこっそり泣いていたんじゃ……","ENG":"Have you been cry–","TWN":"你是不是背著我哭過了……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};